import{c as n,S as h,j as i,m as a}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Thi Đánh giá tư duy (TSA) - ĐH Bách Khoa Hà Nội","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/thi-dgtd-tsa.md","filePath":"hoc-vien/thi-dgtd-tsa.md","lastUpdated":0}'),l={name:"hoc-vien/thi-dgtd-tsa.md"};function c(o,t,r,e,g,u){return h(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="thi-đanh-gia-tu-duy-tsa-đh-bach-khoa-ha-noi" tabindex="-1">Thi Đánh giá tư duy (TSA) - ĐH Bách Khoa Hà Nội <a class="header-anchor" href="#thi-đanh-gia-tu-duy-tsa-đh-bach-khoa-ha-noi" aria-label="Permalink to “Thi Đánh giá tư duy (TSA) - ĐH Bách Khoa Hà Nội”">​</a></h1><p><strong>Đường dẫn (làm bài online):</strong> <code>https://lamsonedutech.vn/luyen-tap/lam-kiem-tra-online-dgtd/:idExam/:time/:idExamUser/:idCourse</code></p><h2 id="ve-ky-thi-tsa" tabindex="-1">Về kỳ thi TSA <a class="header-anchor" href="#ve-ky-thi-tsa" aria-label="Permalink to “Về kỳ thi TSA”">​</a></h2><p><strong>Đánh giá tư duy (ĐGTD / TSA)</strong> là kỳ thi của <strong>Đại học Bách Khoa Hà Nội (HUST)</strong>, dùng để xét tuyển vào HUST và một số trường kỹ thuật-kinh tế khác. Đề thi nhấn mạnh <strong>năng lực tư duy</strong> thay vì học vẹt.</p><h2 id="cau-truc-đe-thi-tsa" tabindex="-1">Cấu trúc đề thi TSA <a class="header-anchor" href="#cau-truc-đe-thi-tsa" aria-label="Permalink to “Cấu trúc đề thi TSA”">​</a></h2><p>Đề có <strong>3 phần</strong>, <strong>150 phút</strong>, <strong>100 câu</strong>:</p><table tabindex="0"><thead><tr><th style="text-align:center;">Phần</th><th>Tên phần</th><th>Mục đích</th><th style="text-align:center;">Thời gian</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>1</strong></td><td>Tư duy Toán học</td><td>Logic &amp; vận dụng toán trong các tình huống mới</td><td style="text-align:center;">60 phút</td></tr><tr><td style="text-align:center;"><strong>2</strong></td><td>Tư duy Đọc hiểu</td><td>Đọc nhanh, nắm ý, suy luận từ văn bản (tiếng Việt + tiếng Anh chuyên ngành)</td><td style="text-align:center;">30 phút</td></tr><tr><td style="text-align:center;"><strong>3</strong></td><td>Tư duy Khoa học / Giải quyết vấn đề</td><td>Vật lý, Hóa học, Sinh học, dữ liệu, biểu đồ - giải quyết tình huống</td><td style="text-align:center;">60 phút</td></tr></tbody></table><p>Dạng câu:</p><ul><li><strong>Trắc nghiệm 1 đáp án (A/B/C/D)</strong>.</li><li><strong>Nhiều đáp án đúng</strong>.</li><li><strong>Đúng / Sai từng ý</strong> (chùm 4 ý a-b-c-d, tính điểm từng ý).</li><li><strong>Điền đáp án ngắn</strong> (số / từ).</li></ul><h2 id="tim-đe-tsa-o-đau" tabindex="-1">Tìm đề TSA ở đâu? <a class="header-anchor" href="#tim-đe-tsa-o-đau" aria-label="Permalink to “Tìm đề TSA ở đâu?”">​</a></h2><ul><li>Trang chủ → mục <strong>&quot;Luyện thi ĐGTD (TSA)&quot;</strong>.</li><li>Trong khóa &quot;Luyện thi ĐGTD&quot; → tab Đề thi thực chiến.</li><li>Menu <strong>Bộ đề thi → TSA</strong>.</li></ul><h2 id="truoc-khi-vao-thi" tabindex="-1">Trước khi vào thi <a class="header-anchor" href="#truoc-khi-vao-thi" aria-label="Permalink to “Trước khi vào thi”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Chuẩn bị</p><ul><li>Máy tính / laptop, <strong>không dùng điện thoại</strong>.</li><li>Tai nghe / loa (nếu đề có nội dung audio).</li><li>Giấy nháp + máy tính cầm tay (kỳ thi thật có cho dùng máy tính cầm tay, đề mẫu cũng vậy).</li><li>Internet ổn định, máy đủ pin.</li><li>150 phút thời gian liên tục, không gián đoạn.</li></ul></div><h2 id="giao-dien-lam-bai-tsa" tabindex="-1">Giao diện làm bài TSA <a class="header-anchor" href="#giao-dien-lam-bai-tsa" aria-label="Permalink to “Giao diện làm bài TSA”">​</a></h2><h3 id="đong-ho-chung" tabindex="-1">Đồng hồ chung <a class="header-anchor" href="#đong-ho-chung" aria-label="Permalink to “Đồng hồ chung”">​</a></h3><ul><li>TSA thường dùng <strong>1 đồng hồ chung 150 phút</strong> (khác HSA chia 3 đồng hồ).</li><li>Học viên tự phân bổ thời gian.</li><li>Có thể <strong>đi qua lại</strong> giữa 3 phần và mọi câu.</li></ul><h3 id="phan-1-tu-duy-toan-hoc" tabindex="-1">Phần 1 - Tư duy Toán học <a class="header-anchor" href="#phan-1-tu-duy-toan-hoc" aria-label="Permalink to “Phần 1 - Tư duy Toán học”">​</a></h3><ul><li>Mở đầu, thường ~40 câu.</li><li>Câu hỏi giả định bối cảnh: bài toán thực tế, đố tư duy, lập luận.</li></ul><h3 id="phan-2-tu-duy-đoc-hieu" tabindex="-1">Phần 2 - Tư duy Đọc hiểu <a class="header-anchor" href="#phan-2-tu-duy-đoc-hieu" aria-label="Permalink to “Phần 2 - Tư duy Đọc hiểu”">​</a></h3><ul><li>Có <strong>đoạn văn dài</strong> (1-2 trang) + câu hỏi đi kèm.</li><li>Có thể có đoạn <strong>tiếng Anh chuyên ngành</strong> kỹ thuật.</li></ul><h3 id="phan-3-khoa-hoc-giai-quyet-van-đe" tabindex="-1">Phần 3 - Khoa học / Giải quyết vấn đề <a class="header-anchor" href="#phan-3-khoa-hoc-giai-quyet-van-đe" aria-label="Permalink to “Phần 3 - Khoa học / Giải quyết vấn đề”">​</a></h3><ul><li>Nhiều bài có <strong>biểu đồ, đồ thị, bảng số liệu</strong>.</li><li>Yêu cầu <strong>đọc hiểu dữ liệu + suy luận</strong> hơn là tính toán phức tạp.</li></ul><h3 id="bang-đieu-huong" tabindex="-1">Bảng điều hướng <a class="header-anchor" href="#bang-đieu-huong" aria-label="Permalink to “Bảng điều hướng”">​</a></h3><ul><li>Lưới câu chia theo 3 phần.</li><li>Có thể <strong>đánh dấu cờ</strong> câu khó.</li></ul><h2 id="sau-khi-nop-bai" tabindex="-1">Sau khi nộp bài <a class="header-anchor" href="#sau-khi-nop-bai" aria-label="Permalink to “Sau khi nộp bài”">​</a></h2><p>Trang kết quả TSA hiển thị:</p><h3 id="tong-điem" tabindex="-1">Tổng điểm <a class="header-anchor" href="#tong-điem" aria-label="Permalink to “Tổng điểm”">​</a></h3><ul><li>Hệ thống quy về thang điểm <strong>chuẩn TSA</strong> (thường 100 điểm hoặc theo cấu hình HUST).</li><li>So với mặt bằng học viên cùng đề.</li></ul><h3 id="điem-theo-phan" tabindex="-1">Điểm theo phần <a class="header-anchor" href="#điem-theo-phan" aria-label="Permalink to “Điểm theo phần”">​</a></h3><table tabindex="0"><thead><tr><th>Phần</th><th>Điểm</th><th>/ Tối đa</th></tr></thead><tbody><tr><td>Tư duy Toán học</td><td>...</td><td>~40</td></tr><tr><td>Tư duy Đọc hiểu</td><td>...</td><td>~20</td></tr><tr><td>Tư duy Khoa học</td><td>...</td><td>~40</td></tr></tbody></table><h3 id="phan-tich-chi-tiet" tabindex="-1">Phân tích chi tiết <a class="header-anchor" href="#phan-tich-chi-tiet" aria-label="Permalink to “Phân tích chi tiết”">​</a></h3><ul><li>Câu đúng / sai theo <strong>chủ đề con</strong> (đại số, hình học, đọc hiểu phân tích, đọc hiểu thông tin, vật lý cơ học, hóa hữu cơ, ...).</li><li><strong>So sánh với điểm chuẩn HUST các năm trước</strong> (nếu hệ thống tích hợp).</li><li><strong>Gợi ý chuyên đề cần ôn</strong>.</li></ul><h2 id="chien-luoc-lam-đe-tsa" tabindex="-1">Chiến lược làm đề TSA <a class="header-anchor" href="#chien-luoc-lam-đe-tsa" aria-label="Permalink to “Chiến lược làm đề TSA”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Khác biệt với HSA</p><ul><li>TSA <strong>ít nhớ máy móc</strong>, nhiều <strong>tư duy</strong>. Đọc kỹ đề, không vội.</li><li>Câu <strong>Đúng/Sai 4 ý</strong> rất hay xuất hiện - đánh sai 1 ý có thể mất điểm cả câu (tùy quy chế).</li><li>Phần Đọc hiểu yêu cầu <strong>đọc nhanh, lọc ý chính</strong> - luyện kỹ năng đọc lướt.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Phân bổ thời gian</p><ul><li>Toán: 60 phút, Đọc hiểu: 30 phút, Khoa học: 60 phút.</li><li>Để dành <strong>5-10 phút cuối</strong> kiểm tra lại các câu đánh dấu.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Câu Đúng/Sai 4 ý</p><ul><li>Đọc kỹ từng ý nhỏ a-b-c-d.</li><li>Đừng vội kết luận - mỗi ý là 1 nhận định độc lập.</li><li>Tốt nhất giải nháp ra giấy trước khi tích.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Câu điền đáp án</p><ul><li>Đề thường yêu cầu <strong>đáp án dạng số nguyên / thập phân</strong>.</li><li>Đọc kỹ &quot;lấy 1 chữ số sau dấu phẩy&quot; hay &quot;làm tròn đến 0.01&quot;.</li><li>Sai định dạng = sai câu, dù đúng ý.</li></ul></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi có 150 phút - phân bổ thế nào tối ưu?</strong> → Tham khảo trên (60-30-60 + 10 phút check). Bắt đầu phần mạnh nhất để <strong>tích lũy điểm chắc</strong>, rồi mới đến phần yếu.</p><p><strong>Câu Đúng/Sai 4 ý tính điểm thế nào?</strong> → Tùy quy chế:</p><ul><li>Đúng cả 4 ý → 1 điểm (hoặc 1.0).</li><li>Đúng 3 ý → 0.75.</li><li>Đúng 2 → 0.5.</li><li>Đúng 1 → 0.25.</li><li>0 ý đúng → 0.</li></ul><p><strong>Đề TSA có cho dùng máy tính cầm tay không?</strong> → Kỳ thi thật cho phép Casio/Vinacal trong danh mục. Đề mẫu trên hệ thống không kiểm soát - bạn nên <strong>luyện thói quen dùng máy tính cầm tay</strong> giống lúc thi thật.</p><p><strong>Điểm TSA của tôi có quy đổi sang HSA được không?</strong> → Không. Hai kỳ thi khác cấu trúc, khác thang điểm. Mỗi trường ĐH có quy chế riêng - hãy tra cứu trên trang tuyển sinh.</p><p><strong>Tôi muốn so sánh kết quả các lần thi thử.</strong> → Vào <a href="./lich-su-xep-hang">Lịch sử &amp; Bảng xếp hạng</a> - hệ thống có biểu đồ tiến bộ qua các lần.</p>',44)])])}const p=n(l,[["render",c]]);export{d as __pageData,p as default};
